import React, { lazy, Suspense, useEffect, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { PageHeader } from '../components/PageHeader';
import { GanttView } from '../components/GanttView';
import { ExportTasksModal } from '../components/ExportTasksModal';
import { LayoutGrid, ChartGantt, FileDown } from 'lucide-react';

// Lazy load Kanban widget
const Kanban = lazy(() =>
  import('../widgets/Kanban').then((module) => ({ default: module.Kanban }))
);

// Loading fallback
const WidgetLoader = () => (
  <div className="bento-card p-6 h-[600px] animate-pulse">
    <div className="h-full bg-gradient-to-r from-neutral-200 to-neutral-300 dark:from-neutral-800 dark:to-neutral-700 rounded"></div>
  </div>
);

type TaskView = 'kanban' | 'gantt';

const VALID_VIEWS: TaskView[] = ['kanban', 'gantt'];

/**
 * Tasks Page - Kanban board and Gantt timeline
 * Full-featured task management with drag-and-drop and timeline views
 *
 * UI pattern matches Schedule page with underline-accent tab bar
 */
export const Tasks: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();

  // Read initial view from URL query params
  const getViewFromUrl = (): TaskView => {
    const params = new URLSearchParams(location.search);
    const view = params.get('view');
    if (view && VALID_VIEWS.includes(view as TaskView)) {
      return view as TaskView;
    }
    return 'kanban'; // Default view
  };

  const [activeView, setActiveView] = useState<TaskView>(getViewFromUrl);
  const [showExportModal, setShowExportModal] = useState(false);

  // Update view when URL changes (e.g., from sidebar navigation)
  useEffect(() => {
    const newView = getViewFromUrl();
    if (newView !== activeView) {
      setActiveView(newView);
    }
  }, [location.search]);

  useEffect(() => {
    document.title = 'Neuman Brain';
  }, []);

  // Update URL when view changes
  const handleViewChange = (view: TaskView) => {
    setActiveView(view);
    navigate(`/tasks?view=${view}`, { replace: true });
  };

  return (
    <div className="tasks-page flex flex-col h-full">
      <PageHeader />

      {/* Tab Navigation - matches Schedule page style */}
      <div className="mb-6 border-b border-border-light dark:border-border-dark">
        <div className="flex justify-between items-center">
          <div className="flex gap-1">
            <button
              onClick={() => handleViewChange('kanban')}
              className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
                activeView === 'kanban'
                  ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
                  : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
              }`}
            >
              <LayoutGrid className="w-4 h-4" />
              Kanban
            </button>
            <button
              onClick={() => handleViewChange('gantt')}
              className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
                activeView === 'gantt'
                  ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
                  : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
              }`}
              title="Gantt-style timeline view"
            >
              <ChartGantt className="w-4 h-4" />
              Timeline
            </button>
          </div>

          {/* Export Button */}
          <button
            onClick={() => setShowExportModal(true)}

import React, { useState } from 'react';
import { AlertCircle, ChevronDown, ChevronUp, RefreshCw } from 'lucide-react';

export interface ErrorMessageProps {
  /**
   * Error title/heading
   */
  title: string;

  /**
   * Error description/message
   */
  message: string;

  /**
   * Optional technical error details (collapsible)
   */
  details?: string;

  /**
   * Optional retry handler
   */
  onRetry?: () => void;

  /**
   * Optional dismiss handler
   */
  onDismiss?: () => void;

  /**
   * Error severity level
   * @default 'error'
   */
  variant?: 'error' | 'warning' | 'info';

  /**
   * Size variant
   * @default 'md'
   */
  size?: 'sm' | 'md' | 'lg';

  /**
   * Custom className
   */
  className?: string;
}

const variantConfig = {
  error: {
    background: 'bg-red-50 dark:bg-red-900/20',
    border: 'border-red-400 dark:border-red-600',
    icon: 'text-red-600 dark:text-red-400',
    title: 'text-red-900 dark:text-red-300',
    message: 'text-red-800 dark:text-red-400',
  },
  warning: {
    background: 'bg-yellow-50 dark:bg-yellow-900/20',
    border: 'border-yellow-400 dark:border-yellow-600',
    icon: 'text-yellow-600 dark:text-yellow-400',
    title: 'text-yellow-900 dark:text-yellow-300',
    message: 'text-yellow-800 dark:text-yellow-400',
  },
  info: {
    background: 'bg-blue-50 dark:bg-blue-900/20',
    border: 'border-blue-400 dark:border-blue-600',
    icon: 'text-blue-600 dark:text-blue-400',
    title: 'text-blue-900 dark:text-blue-300',
    message: 'text-blue-800 dark:text-blue-400',
  },
};

const sizeConfig = {
  sm: {
    padding: 'p-3',
    icon: 'w-5 h-5',
    title: 'text-sm',
    message: 'text-xs',
    button: 'text-xs px-2 py-1',
  },
  md: {
    padding: 'p-4',
    icon: 'w-6 h-6',
    title: 'text-base',
    message: 'text-sm',
    button: 'text-sm px-3 py-1.5',
  },
  lg: {
    padding: 'p-6',
    icon: 'w-8 h-8',
    title: 'text-xl',
    message: 'text-base',
    button: 'text-base px-4 py-2',
  },
};

/**
 * ErrorMessage - Comprehensive error display component with retry and details
 *
 * @example
 * // Simple error
 * <ErrorMessage
 *   title="Import Failed"
 *   message="The ICS file could not be imported. Please check the file format and try again."
 *   onRetry={() => retryImport()}
 * />
 *
 * @example
 * // With technical details
 * <ErrorMessage
 *   title="Connection Error"
 *   message="Failed to connect to the server"
 *   details={error.stack}
 *   onRetry={() => reconnect()}
 * />
 *
 * @example
 * // Warning variant
 * <ErrorMessage
 *   variant="warning"
 *   title="Storage Almost Full"
 *   message="You've used 90% of your browser storage. Consider exporting and deleting old data."
 * />
 */
export const ErrorMessage: React.FC<ErrorMessageProps> = ({
  title,
  message,
  details,
  onRetry,
  onDismiss,
  variant = 'error',
  size = 'md',
  className = '',
}) => {
  const [showDetails, setShowDetails] = useState(false);

  const variantStyles = variantConfig[variant];
  const sizeStyles = sizeConfig[size];

  return (
    <div
      className={`${sizeStyles.padding} ${variantStyles.background} ${variantStyles.border} border-2 rounded-lg ${className}`}
      role="alert"
    >
      <div className="flex items-start gap-3">
        {/* Icon */}
        <AlertCircle className={`${sizeStyles.icon} ${variantStyles.icon} flex-shrink-0 mt-0.5`} />

        {/* Content */}
        <div className="flex-1 min-w-0">
          {/* Title */}
          <h3 className={`${sizeStyles.title} font-bold ${variantStyles.title} mb-1`}>
            {title}
          </h3>

          {/* Message */}
          <p className={`${sizeStyles.message} ${variantStyles.message}`}>
            {message}
          </p>

          {/* Technical Details (Collapsible) */}
          {details && (
            <div className="mt-3">
              <button
                onClick={() => setShowDetails(!showDetails)}
                className={`${sizeStyles.button} flex items-center gap-1 ${variantStyles.message} hover:opacity-75 transition-opacity font-medium`}
              >
                {showDetails ? (
                  <>
                    <ChevronUp className="w-4 h-4" />
                    Hide details
                  </>
                ) : (
                  <>
                    <ChevronDown className="w-4 h-4" />
                    Show details
                  </>
                )}
              </button>

              {showDetails && (
                <div className="mt-2 p-3 bg-surface-light dark:bg-surface-dark-elevated rounded border border-border-light dark:border-border-dark overflow-auto max-h-40">
                  <pre className="text-xs text-text-light-secondary dark:text-text-dark-secondary whitespace-pre-wrap break-words font-mono">
                    {details}
                  </pre>
                </div>
              )}
            </div>
          )}

          {/* Actions */}
          {(onRetry || onDismiss) && (
            <div className="flex items-center gap-2 mt-4">
              {onRetry && (
                <button
                  onClick={onRetry}
                  className={`${sizeStyles.button} inline-flex items-center gap-1 ${variantStyles.message} bg-white dark:bg-surface-dark hover:opacity-75 border border-current rounded transition-opacity font-medium`}
                >
                  <RefreshCw className="w-4 h-4" />
                  Retry
                </button>
              )}
              {onDismiss && (
                <button
                  onClick={onDismiss}
                  className={`${sizeStyles.button} ${variantStyles.message} hover:opacity-75 transition-opacity`}
                >
                  Dismiss
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Loader2 } from 'lucide-react';

export interface LoadingSpinnerProps {
  /**
   * Size of the spinner
   * @default 'md'
   */
  size?: 'sm' | 'md' | 'lg' | 'xl';

  /**
   * Optional message to display below the spinner
   */
  message?: string;

  /**
   * Whether to center the spinner in its container
   * @default false
   */
  center?: boolean;

  /**
   * Whether to show full-screen overlay (useful for page-level loading)
   * @default false
   */
  fullScreen?: boolean;

  /**
   * Custom className for additional styling
   */
  className?: string;
}

const sizeClasses = {
  sm: 'w-4 h-4',
  md: 'w-8 h-8',
  lg: 'w-12 h-12',
  xl: 'w-16 h-16',
};

const textSizeClasses = {
  sm: 'text-sm',
  md: 'text-base',
  lg: 'text-lg',
  xl: 'text-xl',
};

/**
 * LoadingSpinner - Reusable loading indicator with optional message
 *
 * @example
 * // Simple spinner
 * <LoadingSpinner />
 *
 * @example
 * // With message
 * <LoadingSpinner message="Loading your notes..." />
 *
 * @example
 * // Centered
 * <LoadingSpinner center message="Please wait..." />
 *
 * @example
 * // Full-screen loading overlay
 * <LoadingSpinner fullScreen message="Importing calendar..." />
 */
export const LoadingSpinner: React.FC<LoadingSpinnerProps> = ({
  size = 'md',
  message,
  center = false,
  fullScreen = false,
  className = '',
}) => {
  const spinnerContent = (
    <div className={`flex flex-col items-center gap-3 ${center ? 'justify-center' : ''} ${className}`}>
      <Loader2
        className={`${sizeClasses[size]} animate-spin text-accent-blue dark:text-accent-cyan`}
        aria-label="Loading"
      />
      {message && (
        <p className={`${textSizeClasses[size]} text-text-light-secondary dark:text-text-dark-secondary text-center max-w-md`}>
          {message}
        </p>
      )}
    </div>
  );

  if (fullScreen) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-surface-light/80 dark:bg-surface-dark/80 backdrop-blur-sm">
        {spinnerContent}
      </div>
    );
  }

  if (center) {
    return (
      <div className="flex items-center justify-center w-full h-full min-h-[200px]">
        {spinnerContent}
      </div>
    );
  }

  return spinnerContent;
};

