    57→            aria-label={action.label}
    58→          >
    59→            {action.label}
    60→          </button>
    61→        )}
    62→
    63→        {/* Close Button */}
    64→        <button
    65→          onClick={onClose}
    66→          className="ml-2 text-text-dark-secondary hover:text-text-dark-primary dark:text-text-light-secondary dark:hover:text-text-light-primary transition-all duration-standard ease-smooth"
    67→          aria-label="Close notification"
    68→        >
